import numpy as np

def rmsnorm(
    x: np.ndarray,
    gamma: np.ndarray,
    eps: float = 1e-6
) -> np.ndarray:
    rms = np.sqrt(np.mean(x ** 2, axis=-1, keepdims=True) + eps)  # (n, 1)
    x_hat = x / rms                                                  # (n, d)
    return gamma * x_hat                                             # (n, d)
